   740→// Select evenly-spaced key frames from a larger set
   741→function selectKeyFrames(frames, count) {
   742→  const result = [];
   743→  const step = (frames.length - 1) / (count - 1);
   744→  for (let i = 0; i < count; i++) {
   745→    result.push(frames[Math.round(i * step)]);
   746→  }
   747→  return result;
   748→}
