   750→// Analyze speech transcription for communication quality
   751→function analyzeSpeechPatterns(transcription, durationSeconds) {
   752→  const words = transcription.trim().split(/\s+/).filter(w => w.length > 0);
   753→  const wordCount = words.length;
   754→  const wpm = durationSeconds > 0 ? Math.round((wordCount / durationSeconds) * 60) : 0;
   755→
   756→  // Filler word detection
   757→  const fillerWords = ['um', 'uh', 'like', 'you know', 'so', 'basically', 'actually', 'literally', 'right', 'okay so', 'i mean'];
   758→  const fillerCounts = {};
   759→  let totalFillers = 0;
   760→  const lowerTranscription = transcription.toLowerCase();
   761→
   762→  for (const filler of fillerWords) {
   763→    const regex = new RegExp(`\\b${filler}\\b`, 'gi');
   764→    const matches = lowerTranscription.match(regex);
   765→    if (matches && matches.length > 0) {
   766→      fillerCounts[filler] = matches.length;
   767→      totalFillers += matches.length;
   768→    }
   769→  }
   770→
   771→  const fillerRate = wordCount > 0 ? (totalFillers / wordCount) * 100 : 0;
   772→
   773→  // Pace analysis
   774→  let paceAssessment = 'good';
   775→  let paceFeedback = '';
   776→  if (wpm < 100) {
   777→    paceAssessment = 'too_slow';
   778→    paceFeedback = 'Your speaking pace is quite slow. Try to speak more naturally and with more energy. Aim for 120-150 words per minute.';
   779→  } else if (wpm < 120) {
   780→    paceAssessment = 'slightly_slow';
   781→    paceFeedback = 'Your pace is a bit slow. Try to increase your speaking speed slightly for more engaging delivery.';
   782→  } else if (wpm <= 160) {
   783→    paceAssessment = 'good';
   784→    paceFeedback = 'Your speaking pace is natural and easy to follow. Well done!';
   785→  } else if (wpm <= 180) {
   786→    paceAssessment = 'slightly_fast';
   787→    paceFeedback = 'You\'re speaking a bit quickly. Try to slow down slightly and pause between key points.';
   788→  } else {
   789→    paceAssessment = 'too_fast';
   790→    paceFeedback = 'You\'re speaking too fast — this can signal nervousness. Take deliberate pauses between sentences and breathe.';
   791→  }
   792→
   793→  // Sentence structure analysis
   794→  const sentences = transcription.split(/[.!?]+/).filter(s => s.trim().length > 0);
   795→  const avgSentenceLength = sentences.length > 0 ? Math.round(wordCount / sentences.length) : 0;
   796→
   797→  // Communication score (1-10)
   798→  let communicationScore = 7;
   799→  // Penalize for filler words
   800→  if (fillerRate > 5) communicationScore -= 2;
   801→  else if (fillerRate > 3) communicationScore -= 1;
   802→  // Penalize for bad pace
   803→  if (paceAssessment === 'too_slow' || paceAssessment === 'too_fast') communicationScore -= 1.5;
   804→  else if (paceAssessment === 'slightly_slow' || paceAssessment === 'slightly_fast') communicationScore -= 0.5;
   805→  // Reward for good sentence structure
   806→  if (avgSentenceLength >= 10 && avgSentenceLength <= 25) communicationScore += 0.5;
   807→  // Penalize for very short responses
   808→  if (wordCount < 50) communicationScore -= 2;
   809→  else if (wordCount < 100) communicationScore -= 1;
   810→  // Reward for substantial responses
   811→  if (wordCount >= 150 && wordCount <= 400) communicationScore += 0.5;
   812→
   813→  communicationScore = Math.max(1, Math.min(10, Math.round(communicationScore * 10) / 10));
   814→
   815→  return {
   816→    word_count: wordCount,
   817→    duration_seconds: durationSeconds,
   818→    words_per_minute: wpm,
   819→    filler_words: fillerCounts,
   820→    total_fillers: totalFillers,
   821→    filler_rate: Math.round(fillerRate * 10) / 10,
   822→    pace: {
   823→      assessment: paceAssessment,
   824→      wpm,
   825→      feedback: paceFeedback
   826→    },
   827→    sentence_count: sentences.length,
   828→    avg_sentence_length: avgSentenceLength,
   829→    communication_score: communicationScore,
   830→    tips: generateSpeechTips(fillerRate, wpm, wordCount, totalFillers, fillerCounts)
   831→  };
   832→}
   833→
   834→function generateSpeechTips(fillerRate, wpm, wordCount, totalFillers, fillerCounts) {
   835→  const tips = [];
   836→
   837→  if (fillerRate > 3) {
   838→    const topFillers = Object.entries(fillerCounts)
   839→      .sort((a, b) => b[1] - a[1])
   840→      .slice(0, 3)
   841→      .map(([word, count]) => `"${word}" (${count}x)`);
   842→    tips.push(`Reduce filler words — you used ${totalFillers} fillers: ${topFillers.join(', ')}. Try pausing silently instead.`);
   843→  }
   844→
   845→  if (wpm > 160) {
   846→    tips.push('Slow down your pace. Take a breath between key points to let your message land.');
   847→  } else if (wpm < 110) {
   848→    tips.push('Pick up the pace slightly. A faster tempo projects confidence and engagement.');
   849→  }
   850→
   851→  if (wordCount < 80) {
   852→    tips.push('Your response was quite short. Aim for 1-2 minutes of speaking time to give a comprehensive answer.');
   853→  }
   854→
   855→  if (tips.length === 0) {
   856→    tips.push('Strong verbal delivery! Your pace and clarity are good. Keep practicing to maintain consistency.');
   857→  }
   858→
   859→  return tips;
   860→}
