  1204→    : '';
  1205→
  1206→  const prompt = `Generate 25 diverse, high-quality interview questions for a "${role}" position.${jdContext}
  1207→
  1208→Create a mix of question types:
  1209→- 8 behavioral (STAR method) — past experiences, teamwork, leadership, conflict
  1210→- 6 technical — role-specific technical knowledge and problem-solving
  1211→- 6 situational — hypothetical scenarios relevant to the role
  1212→- 3 competency-based — core competencies for this specific role
  1213→- 2 role-specific — unique questions that only apply to this exact position
  1214→
  1215→For each question, vary difficulty: roughly 30% easy, 50% medium, 20% hard.
  1216→
  1217→Return a JSON array where each item has:
  1218→{
  1219→  "question_text": "The interview question",
  1220→  "question_type": "behavioral|technical|situational|competency|role_specific",
  1221→  "difficulty": "easy|medium|hard",
  1222→  "key_points": ["Point 1", "Point 2", "Point 3"],
  1223→  "skills_tested": ["skill1", "skill2"]
  1224→}
  1225→
  1226→Make questions specific to the "${role}" role — NOT generic. Reference actual responsibilities, tools, and challenges someone in this role would face.
  1227→
  1228→Only return the JSON array, no other text.`;
  1229→
  1230→  const result = await chat(prompt, {
  1231→    system: 'You are a senior hiring manager who has conducted thousands of interviews. Generate realistic, probing questions that distinguish great candidates from average ones. Always return valid JSON.',
  1232→    maxTokens: 8192,
  1233→    subscriptionId: options.subscriptionId,
  1234→    module: 'mock_interview', feature: 'question_bank'
  1235→  });
  1236→
  1237→  try {
  1238→    return JSON.parse(result);
  1239→  } catch (e) {
  1240→    const match = result.match(/\[[\s\S]*\]/);
  1241→    if (match) return JSON.parse(match[0]);
  1242→    throw new Error('Failed to generate question bank');
  1243→  }
  1244→}
