  1246→// AI interviewer conducts a conversational interview turn
  1247→async function conductInterviewTurn(conversation, baseQuestions, currentQuestionIndex, targetRole, options = {}) {
  1248→  // Send last 12 turns for better context on follow-ups
  1249→  const recentConvo = conversation.slice(-12);
  1250→  const convoText = recentConvo.map(turn => {
  1251→    if (turn.role === 'interviewer') return `INTERVIEWER: ${turn.text}`;
  1252→    return `CANDIDATE: ${turn.text}`;
  1253→  }).join('\n\n');
  1254→
  1255→  const candidateTurnCount = conversation.filter(t => t.role === 'candidate').length;
  1256→  const followUpCount = conversation.filter(t => t.role === 'interviewer' && (t.action === 'follow_up' || t.action === 'challenge')).length;
  1257→  const remainingQuestions = baseQuestions.slice(currentQuestionIndex);
  1258→  const nextPlannedQuestion = remainingQuestions.length > 0
  1259→    ? remainingQuestions[0].question_text
  1260→    : null;
  1261→
  1262→  // Count consecutive follow-ups on the current topic
  1263→  let consecutiveFollowUps = 0;
  1264→  for (let i = conversation.length - 1; i >= 0; i--) {
  1265→    const t = conversation[i];
  1266→    if (t.role === 'interviewer' && (t.action === 'follow_up' || t.action === 'challenge')) {
  1267→      consecutiveFollowUps++;
  1268→    } else if (t.role === 'interviewer' && t.action === 'transition') {
  1269→      break;
  1270→    } else if (t.role === 'candidate') {
  1271→      continue; // skip candidate turns when counting
  1272→    }
  1273→  }
  1274→
  1275→  const prompt = `You are conducting a mock interview for a "${targetRole}" position. You have ${remainingQuestions.length} planned questions remaining.
  1276→
  1277→CONVERSATION SO FAR:
  1278→${convoText}
  1279→
  1280→${nextPlannedQuestion ? `NEXT PLANNED QUESTION (use when ready to move on): "${nextPlannedQuestion}"` : 'All planned questions covered.'}
  1281→
  1282→FOLLOW-UP COUNT on current topic: ${consecutiveFollowUps}
  1283→
  1284→YOUR TASK: Act like a real interviewer. After the candidate answers:
  1285→
  1286→1. **FOLLOW UP** if the answer is:
  1287→   - Vague or surface-level ("I worked on a project" → ask WHAT project, what was the challenge)
  1288→   - Missing specifics (no metrics, no concrete examples, no details about their role)
  1289→   - Interesting but unexplored (they mentioned something worth digging into)
  1290→   - Missing the "so what" (they described what happened but not the impact/result)
  1291→   You can ask MULTIPLE follow-ups on the same topic. Keep probing until you have real depth.
  1292→
  1293→2. **TRANSITION** to the next planned question when:
  1294→   - The candidate gave a thorough, specific answer with concrete examples
  1295→   - You've already asked 2-3 follow-ups and have sufficient depth
  1296→   - The candidate clearly has nothing more to add on this topic
  1297→
  1298→3. **WRAP UP** when: ${candidateTurnCount >= 6 ? 'You feel you have enough data (6+ exchanges completed)' : 'NOT YET — keep interviewing, only ' + candidateTurnCount + ' exchanges so far'}
  1299→
  1300→React to their answer specifically (1-2 sentences — reference something concrete they said, NOT generic filler like "Thank you for that response" or "That's helpful"). Show you actually listened. Example good reactions: "That 40% improvement in pipeline throughput is impressive — how did you measure that?" or "Interesting that you chose to refactor first rather than ship the feature." Example bad reactions: "Thank you for sharing that." or "That's great, thanks."
  1301→
  1302→Return JSON: {"reaction":"1-2 sentences referencing SPECIFIC details from their answer","action":"follow_up|challenge|transition|wrap_up","question":"your next question","score_hint":1-10,"notes":"brief note on answer quality"}`;
  1303→
  1304→  const result = await chat(prompt, {
  1305→    system: `You are Alex, an experienced ${targetRole} interviewer. You conduct interviews like a real person — curious, attentive, and thorough. You don't just read from a script. When a candidate gives a vague answer, you probe deeper. When they mention something interesting, you explore it. You ask follow-up questions naturally, like "Tell me more about that" or "What specifically was your role in that?" or "How did you measure success?" You only move to the next planned question when you're genuinely satisfied with the depth of their answer. Always return valid JSON only.`,
  1306→    maxTokens: 1024,
  1307→    subscriptionId: options.subscriptionId,
  1308→    module: 'mock_interview', feature: 'interview_turn'
  1309→  });
  1310→
  1311→  const parsed = safeParseJSON(result);
  1312→  if (parsed) return parsed;
  1313→  throw new Error('Failed to generate interview turn — could not parse LLM response');
  1314→}
