  1316→// Generate session-end feedback for a mock interview
  1317→// Returns structured format matching practice interview: content + communication + presentation
  1318→async function generateSessionFeedback(conversation, targetRole, options = {}) {
  1319→  const convoText = conversation.map(turn => {
  1320→    if (turn.role === 'interviewer') return `INTERVIEWER: ${turn.text}`;
