  1323→
  1324→  // Calculate basic metrics from the text
  1325→  const candidateTurns = conversation.filter(t => t.role === 'candidate');
  1326→  const allCandidateText = candidateTurns.map(t => t.text).join(' ');
  1327→  const wordCount = allCandidateText.split(/\s+/).filter(w => w).length;
  1328→  const questionCount = conversation.filter(t => t.role === 'interviewer').length;
  1329→
  1330→  // Estimate duration from timestamps
  1331→  let durationSeconds = 0;
  1332→  if (conversation.length >= 2) {
  1333→    const first = new Date(conversation[0].timestamp || Date.now());
  1334→    const last = new Date(conversation[conversation.length - 1].timestamp || Date.now());
  1335→    durationSeconds = Math.max(60, Math.round((last - first) / 1000));
  1336→  }
  1337→  const wpm = durationSeconds > 0 ? Math.round(wordCount / (durationSeconds / 60)) : 120;
  1338→
  1339→  const prompt = `You just completed a mock interview for a "${targetRole}" position. Review the full conversation and provide structured feedback in THREE sections matching our coaching format.
  1340→
  1341→FULL INTERVIEW TRANSCRIPT:
  1342→${convoText}
