  1360→    "improvements": ["Specific improvement area with example", "Another improvement"],
  1361→    "covered_points": ["Key competency they demonstrated well"],
  1362→    "missed_points": ["Important area they didn't address or was weak"],
  1363→    "detailed_feedback": "2-3 paragraph deep analysis of their answer quality across ALL questions. Reference patterns: did they improve? Were some topics stronger? Did follow-ups reveal depth or gaps?",
  1364→    "specific_tips": ["Actionable tip 1", "Actionable tip 2", "Actionable tip 3"],
  1365→    "common_mistake": "The most common interview mistake they exhibited",
  1366→    "star_method_usage": { "score": 1-10, "feedback": "How well they structured answers with Situation-Task-Action-Result" },
  1367→    "technical_depth": { "score": 1-10, "feedback": "Depth of technical knowledge and specificity" }
  1368→  },
  1369→
  1370→  "communication": {
  1371→    "score": 1-10,
  1372→    "word_count": ${wordCount},
  1373→    "words_per_minute": ${wpm},
  1374→    "duration_seconds": ${durationSeconds},
  1375→    "filler_words": {"um": 0, "uh": 0, "like": 0, "you know": 0, "so": 0, "basically": 0},
  1376→    "total_fillers": 0,
  1377→    "filler_rate": 0.0,
  1378→    "pace": {
  1379→      "assessment": "good|slightly_fast|slightly_slow|too_fast|too_slow",
  1380→      "wpm": ${wpm},
  1381→      "feedback": "Assessment of their speaking pace and rhythm across the interview"
  1382→    },
  1383→    "tips": ["Speech improvement tip 1", "Tip 2"],
  1384→    "trends": "Did their communication improve/decline over the interview? More confident later? More filler words when nervous?"
  1385→  },
  1386→
  1387→  "question_scores": [
  1388→    { "question_summary": "Brief topic", "score": 1-10, "feedback": "1-2 sentences referencing their actual answer" }
  1389→  ],
  1390→
  1391→  "interview_arc": "How did the interview flow? Did the candidate warm up? Were they stronger on certain topic types? 2-3 sentences about the overall arc.",
  1392→  "top_tip": "Single most impactful thing to work on"
